// тЏЙуЅЄтцДт░ЈжЊЙТјЦ
function urlPxImgQuality(pxImgUrl) {
    const {java, cache} = this
    let settings = this.getFromCacheObject("FNSettings") || this.setDefaultSettings()

    if (pxImgUrl.includes("novel-cover")) {
        if (settings.PIC_SIZE !== "original" && !pxImgUrl.includes("_master1200.jpg")) { // regular
            pxImgUrl = String(pxImgUrl)
                .replace("novel-cover-original", "c/1200x1200/novel-cover-master")
                .replace(/\.(png|jpg|jpeg|gif|webp)$/i, "_master1200.jpg")
        }
        if (settings.PIC_SIZE === "small") {
            pxImgUrl = pxImgUrl.replace("1200x1200", "480x960")
        }
    }
    else if (pxImgUrl.includes("img-original")) {
        if (settings.PIC_SIZE !== "original" && !pxImgUrl.includes("_master1200.jpg")) { // regular
            pxImgUrl = String(pxImgUrl).replace("img-original", "img-master").replace(/\.(png|jpg|jpeg|gif|webp)$/i, "_master1200.jpg")
        }
        if (settings.PIC_SIZE === "small") {
            pxImgUrl = pxImgUrl.replace("img-master", "c/540x540_70/img-master")
        }
    }
    return String(pxImgUrl)
}

// УјитЈќуЏ┤У┐ъжЊЙТјЦ
function urlPxImgUrl(pxImgUrl) {
    const {java, cache} = this
    let settings = this.getFromCacheObject("FNSettings") || this.setDefaultSettings()
    let urlMap = {
        "Linpx": (url) => this.urlPxImgUrlLinpx(url),
        "Pixiv": (url) => this.urlPxImgUrlPixiv(url),
        "PixivCat": (url) => this.urlPxImgUrlPixivCat(url),
        "PixivShojo": (url) => this.urlPxImgUrlPixivShojo(url),
        "CloudFlare": (url) => this.urlPxImgUrlCloudFlare(url),
    }
    let targetFunc = urlMap[settings.PIC_LINK]
    return targetFunc(this.urlPxImgQuality(pxImgUrl))
}
function urlPxImgUrlLinpx(pxImgUrl) {
    if (!pxImgUrl.trim()) return ""
    let url = `https://pximg.furrynovel.ink/?url=${pxImgUrl}&w=800`
    let headers = {"Referer": "https://linpx.ink/"}
    return `${url}, ${JSON.stringify({headers: headers})}`
}
function urlPxImgUrlPixiv(pxImgUrl) {
    const {java, cache} = this
    if (pxImgUrl && !pxImgUrl.trim()) return ""
    let headers = {"Referer": "https://www.pixiv.net/"}

    if (pxImgUrl.trim()) {
        if (pxImgUrl.includes("i.pximg.net")) {
            pxImgUrl = pxImgUrl.replace("https://i.pximg.net", "https://210.140.139.133")
