        } else {
            pxImgUrl = pxImgUrl.replace("https://s.pximg.net", "https://210.140.139.133")
            headers.Host = "s.pximg.net"
        }
    }
    return `${pxImgUrl}, ${JSON.stringify({headers: headers})}`
}
